class LRUCache:
    def __init__(self, capacity, ttl):
        self.cache = OrderedDict()
        self.lock = RLock()
        self.ttl = ttl
    def get(self, key):
        with self.lock:
            if key in self.cache and time.time() - self.cache[key][1] < self.ttl:
                return self.cache[key][0]
            return None

